+/**
+ * Email notification handler — formats and dispatches email notifications
+ * for order lifecycle events.
+ *
+ * Subscribes to EventBus events following the same decoupled pattern as
+ * NotificationService. Each order status transition produces a tailored
+ * email with status-specific subject, body, and metadata.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving order events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailMessage {
+  id: string;
+  to: string;
+  subject: string;
+  htmlBody: string;
+  textBody: string;
+  sentAt: Date;
+}
+
+const STATUS_DISPLAY: Record<string, string> = {
+  pending: 'Pending',
+  confirmed: 'Confirmed',
+  shipped: 'Shipped',
+  delivered: 'Delivered',
+  cancelled: 'Cancelled',
+};
+
+let nextEmailId = 1;
+
+function generateEmailId(): string {
+  return `email-${String(nextEmailId++).padStart(4, '0')}`;
+}
+
+export function resetEmailIdCounter(): void {
+  nextEmailId = 1;
+}
+
+export class EmailNotificationHandler {
+  private logger = new Logger('EmailNotificationHandler');
+  private sentEmails: EmailMessage[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  /**
+   * Register EventBus handlers for order events that trigger emails.
+   */
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      this.handleOrderCreated(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      this.handleOrderStatusChanged(event);
+    });
+  }
+
+  /**
+   * Handle order created — send order confirmation email.
+   */
+  private handleOrderCreated(event: OrderCreatedEvent): void {
+    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);
+
+    const itemRows = event.order.items
+      .map(
+        (item) =>
+          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
+      )
+      .join('');
+
+    const itemsText = event.order.items
+      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
+      .join('\n');
+
+    const htmlBody = [
+      `<h1>Order Confirmation</h1>`,
+      `<p>Hi ${event.user.name},</p>`,
+      `<p>Your order <strong>${event.order.id}</strong> has been placed.</p>`,
+      `<table><thead><tr><th>Item</th><th>Qty</th><th>Price</th></tr></thead>`,
+      `<tbody>${itemRows}</tbody></table>`,
+      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
+    ].join('');
+
+    const textBody = [
+      `Order Confirmation`,
+      ``,
+      `Hi ${event.user.name},`,
+      ``,
+      `Your order ${event.order.id} has been placed.`,
+      ``,
+      itemsText,
+      ``,
+      `Total: $${event.order.total.toFixed(2)}`,
+    ].join('\n');
+
+    this.sendEmail({
+      to: event.user.email,
+      subject: `Order Confirmation — ${event.order.id}`,
+      htmlBody,
+      textBody,
+    });
+  }
+
+  /**
+   * Handle order status change — send status update email.
+   */
+  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
+    this.logger.info(
+      `Sending status email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
+    );
+
+    const displayStatus = STATUS_DISPLAY[event.newStatus] ?? event.newStatus;
+    const subject = this.subjectForStatus(event.order.id, event.newStatus);
+    const { htmlBody, textBody } = this.bodyForStatus(event);
+
+    this.sendEmail({
+      to: event.order.userId,
+      subject,
+      htmlBody,
+      textBody,
+    });
+  }
+
+  /**
+   * Build a status-specific email subject line.
+   */
+  private subjectForStatus(orderId: string, status: string): string {
+    switch (status) {
+      case 'confirmed':
+        return `Order ${orderId} — Confirmed`;
+      case 'shipped':
+        return `Order ${orderId} — Shipped`;
+      case 'delivered':
+        return `Order ${orderId} — Delivered`;
+      case 'cancelled':
+        return `Order ${orderId} — Cancelled`;
+      default:
+        return `Order ${orderId} — Status Update`;
+    }
+  }
+
+  /**
+   * Build status-specific email body content.
+   */
+  private bodyForStatus(event: OrderStatusChangedEvent): {
+    htmlBody: string;
+    textBody: string;
+  } {
+    const displayPrev = STATUS_DISPLAY[event.previousStatus] ?? event.previousStatus;
+    const displayNew = STATUS_DISPLAY[event.newStatus] ?? event.newStatus;
+
+    switch (event.newStatus) {
+      case 'confirmed':
+        return {
+          htmlBody: `<p>Your order <strong>${event.order.id}</strong> has been confirmed and is being prepared.</p>`,
+          textBody: `Your order ${event.order.id} has been confirmed and is being prepared.`,
+        };
+      case 'shipped':
+        return {
+          htmlBody: `<p>Your order <strong>${event.order.id}</strong> has been shipped!</p>`,
+          textBody: `Your order ${event.order.id} has been shipped!`,
+        };
+      case 'delivered':
+        return {
+          htmlBody: `<p>Your order <strong>${event.order.id}</strong> has been delivered. Enjoy!</p>`,
+          textBody: `Your order ${event.order.id} has been delivered. Enjoy!`,
+        };
+      case 'cancelled':
+        return {
+          htmlBody: `<p>Your order <strong>${event.order.id}</strong> has been cancelled.</p>`,
+          textBody: `Your order ${event.order.id} has been cancelled.`,
+        };
+      default:
+        return {
+          htmlBody: `<p>Your order <strong>${event.order.id}</strong> status changed from ${displayPrev} to ${displayNew}.</p>`,
+          textBody: `Your order ${event.order.id} status changed from ${displayPrev} to ${displayNew}.`,
+        };
+    }
+  }
+
+  /**
+   * Send an email (in-memory for this demo).
+   */
+  private sendEmail(params: {
+    to: string;
+    subject: string;
+    htmlBody: string;
+    textBody: string;
+  }): void {
+    const email: EmailMessage = {
+      id: generateEmailId(),
+      to: params.to,
+      subject: params.subject,
+      htmlBody: params.htmlBody,
+      textBody: params.textBody,
+      sentAt: new Date(),
+    };
+    this.sentEmails.push(email);
+    this.logger.info(`Email sent: ${email.id} to ${params.to} — ${params.subject}`);
+  }
+
+  /**
+   * Get all sent emails.
+   */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Get sent emails for a specific recipient.
+   */
+  getEmailsForRecipient(to: string): EmailMessage[] {
+    return this.sentEmails.filter((e) => e.to === to);
+  }
+
+  /**
+   * Get the count of sent emails.
+   */
+  getEmailCount(): number {
+    return this.sentEmails.length;
+  }
+
+  /**
+   * Clear all sent emails (useful for testing).
+   */
+  clearEmails(): void {
+    this.sentEmails = [];
+  }
+}

